// 1. Obtiene el Base64 
let base64String = $input.item.json.content_base64;

// 2. Limpieza profunda (quita encabezados y espacios)
const cleanBase64 = base64String.replace(/^data:application\/pdf;base64,/, "").replace(/\s/g, "");

// 3. Convierte a Buffer
const buffer = Buffer.from(cleanBase64, 'base64');

// 4. Crea el binario que n8n entiende como ARCHIVO
const binaryData = await this.helpers.prepareBinaryData(buffer, 'reporte_ejecucion_final.pdf', 'application/pdf');

return {
  json: { 
    resultado: "Archivo listo",
    nombre: "Reporte_final.pdf" 
  },
  binary: {
    data: binaryData // 'data' es el nombre de la "caja" que contiene el PDF
  }
};
